// Parser l'input du toolWorkflow
const raw = $input.first().json;
let airtableId = '';
if (raw.query && typeof raw.query === 'string') airtableId = raw.query.trim();
else if (raw.chatInput && typeof raw.chatInput === 'string') airtableId = raw.chatInput.trim();
else if (raw.airtable_id) airtableId = raw.airtable_id.trim();
else {
  for (const [k, v] of Object.entries(raw)) {
    if (typeof v === 'string' && (v.startsWith('rec') || v.startsWith('TEST_'))) {
      airtableId = v.trim();
      break;
    }
  }
}
const idMatch = airtableId.match(/(rec[A-Za-z0-9]+|TEST_[A-Za-z0-9_]+)/);
if (idMatch) airtableId = idMatch[1];

return [{ json: { airtable_id: airtableId, has_id: airtableId.length > 0 } }];

// ============================================================
// Construire le prompt Sonnet pour extraction + génération CV
// ============================================================

const j = $('📋 Charger profil complet').first().json;

if (!j || !j.airtable_id) {
  return [{ json: { skip: true, error: 'Profil non trouvé' } }];
}

const systemPrompt = `Tu es un expert en rédaction de CV pour jeunes en insertion professionnelle (16-25 ans).

Tu reçois TOUTES les données disponibles sur un jeune. Ton travail :
1. EXTRAIRE les expériences cachées dans les notes du mentor (resume_suivi) et les conversations
2. VALORISER chaque fait réel de manière professionnelle (sans jamais mentir)
3. STRUCTURER les expériences par catégories de missions (comme un CV de cadre)
4. GÉNÉRER un CV complet au format JSON

RÈGLES ABSOLUES :
- Ne JAMAIS mentionner ASE, MNA, foyer, placement, aide sociale, MLDS, dispositif jeunesse
- Ne JAMAIS inventer d'expérience ou de compétence
- "Je fais le ménage au foyer" → "Entretien des espaces collectifs — Hébergement collectif"
- "Pêche en mer au Sénégal" → "Pêcheur artisanal" avec catégories de missions
- "Arrivé en France" n'est PAS une expérience → ne pas mettre
- "Jamais été scolarisé" → ne pas mentionner, mettre seulement la formation actuelle
- UPE2A → "Parcours de Français Langue Étrangère"
- MLDS → "Formation de remise à niveau"
- Adresse : mettre SEULEMENT la ville (pas l'adresse complète)
- Pas de date de naissance
- Pas de photo
- Langues : format texte "(langue maternelle)", "(courant)", "(niveau intermédiaire)" — PAS de pourcentages

STRUCTURE DU CV :
Chaque expérience doit avoir des CATÉGORIES DE MISSIONS (comme un CV senior) :
- Pour la restauration : "Service : ...", "Préparation : ...", "Hygiène : ..."
- Pour le BTP : "Travaux : ...", "Sécurité : ...", "Matériaux : ..."
- Pour la logistique : "Préparation : ...", "Manutention : ...", "Organisation : ..."
- Pour le commerce : "Vente : ...", "Gestion : ...", "Relation client : ..."
- Adapte les catégories au métier

COMPÉTENCES en 4 catégories :
- Savoir-faire : compétences techniques liées au métier visé
- Compétences humaines : soft skills SPÉCIFIQUES (pas "rigoureux, autonome" qui sont génériques)
- Compétences linguistiques : format "Langue (niveau)" en italique
- Si pertinent : Compétences techniques (outils, logiciels, certifications)

ACCROCHE PROFIL : 3-4 lignes personnalisées, mentionnant le métier visé, une qualité distinctive, et la disponibilité. PAS de copié-collé générique.

Si le jeune a très peu d'expérience, concentre-toi sur :
1. Valoriser au maximum ce qui existe (même informel)
2. Étoffer la section compétences
3. Rédiger un profil accrocheur
4. Le CV doit quand même faire PRO et remplir la page

Réponds UNIQUEMENT en JSON valide :`;

const userPrompt = `DONNÉES DU JEUNE :

Identité :
- Prénom : ${j.prenom || ''}
- Nom : ${j.nom || ''}
- Ville : ${j.ville || ''} (${j.departement || ''})
- Téléphone : ${j.telephone || ''}
- Email : ${j.email || 'non renseigné'}
- Genre : ${j.genre || 'non précisé'}

Formation actuelle :
- Classe : ${j.classe || 'non précisée'}
- Secteur visé : ${j.secteur_vise || 'non précisé'}

Profil :
- MNA : ${j.mna ? 'Oui (ne pas mentionner dans le CV)' : 'Non'}
- Niveau français : ${j.niveau_francais_declare || 'non précisé'}
- Disponibilité : ${j.disponibilite || 'non précisée'}
- Besoins exprimés : ${j.besoins || ''}
- Ce qu'il/elle dit : "${(j.attentes_mentor || '').substring(0, 1000)}"

Compétences inférées par IA :
${j.skills_inferees || 'Aucune'}

Notes du mentor (resume_suivi) — MINE D'OR pour extraire des expériences :
${(j.resume_suivi || 'Pas de notes disponibles').substring(0, 2000)}

Conversations WhatsApp récentes :
${(j.conversations_recentes || 'Aucune').substring(0, 1000)}

---

Génère le CV en JSON avec cette structure exacte :
{
  "prenom_nom": "...",
  "telephone": "...",
  "email": "...",
  "ville": "...",
  "titre": "...",
  "profil": "... (3-4 lignes d'accroche personnalisée)",
  "experiences": [
    {
      "poste": "...",
      "lieu": "...",
      "dates": "...",
      "categories": [
        { "nom": "...", "detail": "..." }
      ]
    }
  ],
  "formations": [
    {
      "diplome": "...",
      "lieu": "...",
      "dates": "...",
      "detail": "... (optionnel : matières, mentions)"
    }
  ],
  "competences": [
    { "categorie": "Savoir-faire", "detail": "..." },
    { "categorie": "Compétences humaines", "detail": "..." },
    { "categorie": "Compétences linguistiques", "detail": "..." }
  ],
  "centres_interet": "... (1 ligne)"
}`;

return [{ json: { systemPrompt, userPrompt, jeune: j, skip: false } }];

// ============================================================
// Construire le HTML du CV à partir de la réponse Sonnet
// ============================================================

const sonnetResp = $('🧠 Claude Sonnet (CV)').first().json;
const jeune = $('📝 Construire prompt CV').first().json.jeune;

// Parser le JSON de Sonnet
let cv = {};
try {
  const text = sonnetResp.content?.[0]?.text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  cv = JSON.parse(cleaned);
} catch(e) {
  return [{ json: { response: 'Erreur lors de la génération du CV. Réessaie dans quelques instants.', error: e.message } }];
}

// Construire le HTML
let html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<style>
  @page { size: A4; margin: 0; }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: Georgia, 'Times New Roman', serif; font-size: 10.5pt; line-height: 1.4; color: #1a1a1a; background: white; width: 210mm; min-height: 297mm; padding: 18mm 20mm 15mm 20mm; }
  .header { text-align: center; margin-bottom: 6mm; }
  .header h1 { font-size: 22pt; font-weight: bold; letter-spacing: 1.5px; margin-bottom: 2mm; }
  .header .contact { font-size: 9.5pt; color: #444; line-height: 1.6; }
  .header .contact a { color: #1a5276; text-decoration: none; }
  .header .titre { font-size: 11pt; font-style: italic; color: #1a5276; margin-top: 3mm; }
  .section-title { text-align: center; font-size: 11pt; font-weight: bold; letter-spacing: 2px; text-transform: uppercase; margin-top: 5mm; margin-bottom: 3mm; border-top: 1px solid #1a1a1a; border-bottom: 1px solid #1a1a1a; padding: 1.5mm 0; }
  .profil { font-size: 10pt; text-align: justify; line-height: 1.5; margin-bottom: 2mm; color: #333; }
  .exp { margin-bottom: 4mm; }
  .exp-header { display: flex; justify-content: space-between; align-items: baseline; margin-bottom: 1mm; }
  .exp-title { font-weight: bold; font-size: 10.5pt; text-transform: uppercase; }
  .exp-dates { font-style: italic; font-size: 9pt; color: #555; }
  .exp-lieu { font-style: italic; font-size: 9.5pt; color: #555; margin-bottom: 1.5mm; }
  .cat { margin-bottom: 1mm; font-size: 10pt; line-height: 1.45; text-align: justify; }
  .cat-name { font-weight: bold; }
  .form { margin-bottom: 3mm; }
  .form-header { display: flex; justify-content: space-between; align-items: baseline; }
  .form-title { font-weight: bold; font-size: 10.5pt; text-transform: uppercase; }
  .form-dates { font-style: italic; font-size: 9pt; color: #555; }
  .form-lieu { font-style: italic; font-size: 9.5pt; color: #555; }
  .form-detail { font-size: 9.5pt; color: #333; margin-top: 0.5mm; }
  .comp-line { margin-bottom: 1.5mm; font-size: 10pt; line-height: 1.5; }
  .comp-cat { font-weight: bold; }
  .interets { font-size: 10pt; color: #333; }
</style>
</head>
<body>\n`;

// Header
html += `<div class="header">\n`;
html += `  <h1>${cv.prenom_nom || jeune.prenom + ' ' + (jeune.nom || '')}</h1>\n`;
html += `  <div class="contact">\n`;
if (cv.telephone) html += `    Téléphone : ${cv.telephone}<br>\n`;
if (cv.email && cv.email !== 'non renseigné') html += `    Email : <a href="mailto:${cv.email}">${cv.email}</a>\n`;
html += `  </div>\n`;
if (cv.titre) html += `  <div class="titre">${cv.titre}</div>\n`;
html += `</div>\n\n`;

// Profil
if (cv.profil) {
  html += `<div class="section-title">Profil</div>\n`;
  html += `<div class="profil">${cv.profil}</div>\n\n`;
}

// Expériences
if (cv.experiences && cv.experiences.length > 0) {
  html += `<div class="section-title">Expérience</div>\n`;
  for (const exp of cv.experiences) {
    html += `<div class="exp">\n`;
    html += `  <div class="exp-header">\n`;
    html += `    <span class="exp-title">${exp.poste || ''}</span>\n`;
    html += `    <span class="exp-dates">${exp.dates || ''}</span>\n`;
    html += `  </div>\n`;
    if (exp.lieu) html += `  <div class="exp-lieu">${exp.lieu}</div>\n`;
    if (exp.categories && exp.categories.length > 0) {
      for (const cat of exp.categories) {
        html += `  <div class="cat"><span class="cat-name">${cat.nom} : </span>${cat.detail}</div>\n`;
      }
    }
    html += `</div>\n`;
  }
  html += `\n`;
}

// Formations
if (cv.formations && cv.formations.length > 0) {
  html += `<div class="section-title">Formation</div>\n`;
  for (const form of cv.formations) {
    html += `<div class="form">\n`;
    html += `  <div class="form-header">\n`;
    html += `    <span class="form-title">${form.diplome || ''}</span>\n`;
    html += `    <span class="form-dates">${form.dates || ''}</span>\n`;
    html += `  </div>\n`;
    if (form.lieu) html += `  <div class="form-lieu">${form.lieu}</div>\n`;
    if (form.detail) html += `  <div class="form-detail">${form.detail}</div>\n`;
    html += `</div>\n`;
  }
  html += `\n`;
}

// Compétences
if (cv.competences && cv.competences.length > 0) {
  html += `<div class="section-title">Compétences</div>\n`;
  for (const comp of cv.competences) {
    html += `<div class="comp-line"><span class="comp-cat">${comp.categorie} : </span>${comp.detail}</div>\n`;
  }
  html += `\n`;
}

// Centres d'intérêt
if (cv.centres_interet) {
  html += `<div class="section-title">Centres d'intérêt</div>\n`;
  html += `<div class="interets">${cv.centres_interet}</div>\n`;
}

html += `</body></html>`;

// Résumé pour l'agent
const nbExp = (cv.experiences || []).length;
const nbForm = (cv.formations || []).length;

let summary = `CV généré pour ${cv.prenom_nom || jeune.prenom} :\n`;
summary += `- Titre : ${cv.titre}\n`;
summary += `- ${nbExp} expérience(s), ${nbForm} formation(s)\n`;
summary += `- Profil : ${(cv.profil || '').substring(0, 100)}...\n`;
if (cv.experiences) {
  cv.experiences.forEach(e => {
    summary += `- Exp: ${e.poste} (${e.dates})\n`;
  });
}
summary += `\nLe CV HTML est prêt. Dis au jeune que son CV est en cours de finalisation.`;

return [{ json: { response: summary, cv_html: html, cv_json: cv } }];
